#include <stdio.h>

int main() {

    int num;
    int isValid = 0;   // Initialize the flag variable to indicate whether the input is valid

    /* Prompt the user to enter a number and read in the input */
    printf("Enter an integer between 1 and 100 (inclusive): ");
    scanf("%d", &num);

    while (!isValid){

        /* Check whether the input is within the valid range */
        if (num >= 1 && num <= 100){

            /* Check whether the input is even or odd */
            if (num % 2 == 0)
                printf("%d is an even number.\n", num);
            else
                printf("%d is an odd number.\n", num);

            isValid = 1;  // Set the flag variable to indicate that the input is valid
        }
        else{
            printf("Invalid input. Please enter an integer between 1 and 100 (inclusive): ");
            scanf("%d", &num);
        }
    }

    return 0;
}

